import React, { useState, useEffect, useRef, useCallback } from 'react';
import { io } from 'socket.io-client';
import SignalChart from './components/SignalChart';
import GestureDisplay from './components/GestureDisplay';
import LogPanel from './components/LogPanel';
import TrainingPage from './components/TrainingPage';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';

const BACKEND_URL = 'http://localhost:5050';

function App() {
  const [activePage, setActivePage] = useState('dashboard');
  const [connected, setConnected] = useState(false);
  const [state, setState] = useState({
    label: '—',
    gesture: '—',
    color: '#ffffff',
    act: 0.0,
  });
  const [logs, setLogs] = useState([]);
  const [running, setRunning] = useState(false);
  const [mode, setMode] = useState('simulated'); // 'simulated' | 'live'
  const [liveOpts, setLiveOpts] = useState({
    host: '0.0.0.0',
    port: '45454',
  });
  const socketRef = useRef(null);
  const flexorRef = useRef([]);
  const extensorRef = useRef([]);

  useEffect(() => {
    const socket = io(BACKEND_URL, {
      transports: ['websocket', 'polling'],
    });
    socketRef.current = socket;

    socket.on('connect', () => setConnected(true));
    socket.on('disconnect', () => {
      setConnected(false);
      setRunning(false);
    });

    socket.on('state', (data) => {
      setState((prev) => ({ ...prev, ...data }));
      if (data.label === 'DONE ✓' || data.label === 'STOPPED') {
        setRunning(false);
      }
    });

    socket.on('log', (data) => {
      setLogs((prev) => {
        const next = [...prev, data.text];
        return next.slice(-50); // keep last 50 entries
      });
    });

    socket.on('signal', (data) => {
      flexorRef.current = data.flexors || [];
      extensorRef.current = data.extensors || [];
    });

    return () => {
      socket.disconnect();
    };
  }, []);

  const handleStart = useCallback(() => {
    if (socketRef.current) {
      socketRef.current.emit('start', {
        mode,
        liveOpts: mode === 'live' ? liveOpts : {},
      });
      setRunning(true);
      setLogs([]);
      flexorRef.current = [];
      extensorRef.current = [];
    }
  }, [mode, liveOpts]);

  const handleStop = useCallback(() => {
    if (socketRef.current) {
      socketRef.current.emit('stop');
      setRunning(false);
    }
  }, []);

  return (
    <div className="app-layout">
      <Sidebar activePage={activePage} onNavigate={setActivePage} />

      <div className="app-main">
        {/* Header */}
        <header className="header">
          <h1 className="title">EMG Gesture Classifier</h1>
          <div className="header-right">
            <span className={`status-dot ${connected ? 'connected' : 'disconnected'}`} />
            <span className="status-text">
              {connected ? 'Connected' : 'Disconnected'}
            </span>
          </div>
        </header>

        {activePage === 'dashboard' && (
          <Dashboard connected={connected} />
        )}

        {activePage === 'training' && (
          <TrainingPage socket={socketRef.current} connected={connected} />
        )}

        {activePage === 'testing' && (<>
        {/* Controls */}
        <div className="controls">
          <div className="mode-toggle">
            <button
              className={`btn btn-mode ${mode === 'simulated' ? 'active' : ''}`}
              onClick={() => setMode('simulated')}
              disabled={running}
            >
              Simulated
            </button>
            <button
              className={`btn btn-mode ${mode === 'live' ? 'active' : ''}`}
              onClick={() => setMode('live')}
              disabled={running}
            >
              Live EMG
            </button>
          </div>

          {mode === 'live' && !running && (
            <div className="live-opts">
              <label>
                Listen IP
                <input
                  type="text"
                  value={liveOpts.host}
                  onChange={(e) => setLiveOpts((o) => ({ ...o, host: e.target.value }))}
                />
              </label>
              <label>
                Port
                <input
                  type="number"
                  value={liveOpts.port}
                  onChange={(e) => setLiveOpts((o) => ({ ...o, port: e.target.value }))}
                />
              </label>
            </div>
          )}

          <button
            className="btn btn-start"
            onClick={handleStart}
            disabled={!connected || running}
          >
            ▶ Start
          </button>
          <button
            className="btn btn-stop"
            onClick={handleStop}
            disabled={!connected || !running}
          >
            ■ Stop
          </button>
        </div>

        <div className="main-grid">
          <GestureDisplay
            label={state.label}
            gesture={state.gesture}
            color={state.color}
            activation={state.act}
          />
          <div className="right-column">
            <SignalChart flexorRef={flexorRef} extensorRef={extensorRef} tOn={1.0} tOff={0.6} />
            <LogPanel logs={logs} />
          </div>
        </div>
        </>)}
      </div>
    </div>
  );
}

export default App;
